Writes content to a file in the workspace. First line of your argument must be the file path, remaining lines are the file content. Example:
src/utils.mjs
export function foo() { return 42; }

workspace.src/chunk.mjs:
export function chunk(arr, size) {
  if (!Array.isArray(arr)) throw new TypeError('First argument must be an array');
  if (size < 1) throw new RangeError('Size must be at least 1');
  const result = [];
  for (let i = 0; i <= arr.length; i += size) {
    result.push(arr.slice(i, i + size));
  }
  return result;
}

workspace.tests/chunk.test.mjs:
import { chunk } from '../src/chunk.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

// Test 1: chunks array of 5 into pairs
const r1 = chunk([1, 2, 3, 4, 5], 2);
assert(JSON.stringify(r1) === JSON.stringify([[1, 2], [3, 4], [5]]), 'chunk([1,2,3,4,5], 2) should be [[1,2],[3,4],[5]] but got ' + JSON.stringify(r1));

// Test 2: empty array returns empty
const r2 = chunk([], 3);
assert(JSON.stringify(r2) === JSON.stringify([]), 'chunk([], 3) should be [] but got ' + JSON.stringify(r2));

// Test 3: single element
const r3 = chunk([42], 5);
assert(JSON.stringify(r3) === JSON.stringify([[42]]), 'chunk([42], 5) should be [[42]] but got ' + JSON.stringify(r3));

// Test 4: size equals array length
const r4 = chunk([1, 2, 3], 3);
assert(JSON.stringify(r4) === JSON.stringify([[1, 2, 3]]), 'chunk([1,2,3], 3) should be [[1,2,3]] but got ' + JSON.stringify(r4));

// Test 5: size of 1
const r5 = chunk([1, 2, 3], 1);
assert(JSON.stringify(r5) === JSON.stringify([[1], [2], [3]]), 'chunk([1,2,3], 1) should be [[1],[2],[3]] but got ' + JSON.stringify(r5));

console.log('ALL TESTS PASSED');
